// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "forge-std/Test.sol";
import "${CONTRACT_PATH}";

contract DoSTest is Test {
    ${CONTRACT_NAME} public target;
    uint256 constant BLOCK_GAS_LIMIT = 30_000_000;

    function setUp() public {
        target = new ${CONTRACT_NAME}();
    }

    function testDoS_SmallInput() public {
        uint256 gasBefore = gasleft();
        target.${FUNCTION_NAME}(10);
        uint256 gasUsed = gasBefore - gasleft();
        emit log_named_uint("Gas used (10 items)", gasUsed);
    }

    function testDoS_MediumInput() public {
        uint256 gasBefore = gasleft();
        target.${FUNCTION_NAME}(100);
        uint256 gasUsed = gasBefore - gasleft();
        emit log_named_uint("Gas used (100 items)", gasUsed);
    }

    function testDoS_LargeInput() public {
        uint256 gasBefore = gasleft();
        target.${FUNCTION_NAME}(1000);
        uint256 gasUsed = gasBefore - gasleft();
        emit log_named_uint("Gas used (1000 items)", gasUsed);

        // If gas exceeds block limit, DoS is possible
        if (gasUsed > BLOCK_GAS_LIMIT / 2) {
            emit log("WARNING: Gas usage exceeds 50% of block limit");
        }
    }

    function testDoS_ExtremeInput() public {
        // This should either revert or use excessive gas
        try target.${FUNCTION_NAME}(10000) {
            uint256 gasUsed = gasleft();
            assertLt(gasUsed, BLOCK_GAS_LIMIT, "Exceeded block gas limit");
        } catch {
            // Expected to revert with large input
            assertTrue(true, "Reverted as expected with extreme input");
        }
    }

    function testDoS_GasScaling() public {
        uint256[] memory inputs = new uint256[](5);
        inputs[0] = 10;
        inputs[1] = 50;
        inputs[2] = 100;
        inputs[3] = 500;
        inputs[4] = 1000;

        uint256 prevGas = 0;
        for (uint256 i = 0; i < inputs.length; i++) {
            uint256 gasBefore = gasleft();
            target.${FUNCTION_NAME}(inputs[i]);
            uint256 gasUsed = gasBefore - gasleft();

            emit log_named_uint("Input size", inputs[i]);
            emit log_named_uint("Gas used", gasUsed);

            if (prevGas > 0) {
                uint256 ratio = (gasUsed * 100) / prevGas;
                emit log_named_uint("Gas ratio vs prev (%)", ratio);
            }
            prevGas = gasUsed;
        }
    }
}
